function getInitialActions(project: StoredProject): ActionStep[] {
    if (project.fullResult) {
        return project.fullResult.levers.map((lever) => ({
            id: crypto.randomUUID(),
            description: lever.action,
            priority: lever.expected_impact,
            status: "todo" as const,
        }));
    }
    return [];
}

const DEFAULT_MILESTONES: Milestone[] = [
    { id: "mvp", title: "MVP", targetDate: "" },
    { id: "users", title: "Premiers Utilisateurs", targetDate: "" },
    { id: "revenue", title: "Premier Revenu", targetDate: "" },
    { id: "scale", title: "Scale", targetDate: "" },
];

export function StructurationWorkspace({ project }: StructurationWorkspaceProps) {
    const [bmc, setBMC] = useState<BMCData>(() => getInitialBMC(project));
    const [actions, setActions] = useState<ActionStep[]>(() => getInitialActions(project));
    const [milestones, setMilestones] = useState<Milestone[]>(DEFAULT_MILESTONES);
    const [newAction, setNewAction] = useState("");
    const [showActionInput, setShowActionInput] = useState(false);
    const [isLoading, setIsLoading] = useState(true);
    const [bmcCardIds, setBmcCardIds] = useState<Record<keyof BMCData, string | null>>({
        valueProposition: null,
        target: null,
        revenueModel: null,
        keyResources: null,
    });

    // Load all data from API
    useEffect(() => {
        async function loadData() {
            try {
                setIsLoading(true);

                // Load BMC fields (BUSINESS type)
                const bmcResponse = await fetch(`/api/projects/${project.id}/cards?type=BUSINESS&phase=VALIDATION`);
                if (bmcResponse.ok) {
                    const bmcData = await bmcResponse.json();
                    const bmcCards: Card[] = bmcData.data || [];
                    const newBMC: BMCData = { ...bmc };
                    const newIds: typeof bmcCardIds = { ...bmcCardIds };

                    bmcCards.forEach((card) => {
                        const field = card.metadata.bmcField as keyof BMCData;
                        if (field && field in newBMC) {
                            newBMC[field] = card.description || "";
                            newIds[field] = card.id;
                        }
                    });

                    if (bmcCards.length > 0) {
                        setBMC(newBMC);
                        setBmcCardIds(newIds);
                    }
                }

                // Load actions (FEATURE type)
                const actionsResponse = await fetch(`/api/projects/${project.id}/cards?type=FEATURE&phase=VALIDATION`);
                if (actionsResponse.ok) {
                    const actionsData = await actionsResponse.json();
                    const actionCards: Card[] = actionsData.data || [];
                    if (actionCards.length > 0) {
                        setActions(actionCards.map(card => ({
                            id: card.id,
                            description: card.label,
                            priority: (card.priority as "HIGH" | "MEDIUM" | "LOW") || "MEDIUM",
                            status: card.validated ? "done" : "todo"
                        })));
                    }
                }

                // Load milestones (NOTE type with milestone metadata)
                const milestonesResponse = await fetch(`/api/projects/${project.id}/cards?type=NOTE&phase=VALIDATION`);
                if (milestonesResponse.ok) {
                    const milestonesData = await milestonesResponse.json();
                    const milestoneCards: Card[] = milestonesData.data || [];
                    const apiMilestones = milestoneCards
                        .filter(card => card.metadata.isMilestone)
                        .map(card => ({
                            id: card.id,
                            title: card.label,
                            targetDate: card.metadata.targetDate || ""
                        }));
                    if (apiMilestones.length > 0) {
                        setMilestones(apiMilestones);
                    }
                }
            } catch (error) {
                console.error("Failed to load Lab 2 data:", error);
            } finally {
                setIsLoading(false);
            }
        }
        loadData();
    }, [project.id]);

    function updateBMC(field: keyof BMCData, value: string) {
        setBMC((prev) => ({ ...prev, [field]: value }));
    }

    function addAction() {
        if (!newAction.trim()) return;
        setActions([...actions, {
            id: crypto.randomUUID(),
            description: newAction.trim(),
            priority: "MEDIUM",
            status: "todo",
        }]);
        setNewAction("");
        setShowActionInput(false);
    }

    function toggleAction(id: string) {
        setActions(actions.map((a) => a.id === id ? { ...a, status: a.status === "done" ? "todo" : "done" } : a));
    }

    function removeAction(id: string) {
        setActions(actions.filter((a) => a.id !== id));
    }

    function updateMilestone(id: string, field: "title" | "targetDate", value: string) {
        setMilestones(milestones.map((m) => m.id === id ? { ...m, [field]: value } : m));
    }

    const bmcBlocks: { key: keyof BMCData; title: string; placeholder: string }[] = [
        { key: "valueProposition", title: "Proposition de Valeur", placeholder: "Quel probleme resolvez-vous et comment ?" },
        { key: "target", title: "Cible", placeholder: "Qui sont vos clients ? Quel segment adressez-vous ?" },
        { key: "revenueModel", title: "Modele de Revenus", placeholder: "Comment gagnez-vous de l'argent ?" },
        { key: "keyResources", title: "Ressources Cles", placeholder: "Quelles ressources techniques et humaines ?" },
    ];

    return (
        <main className="flex-1 overflow-y-auto bg-[#22242B] p-8">
            <div className="max-w-4xl mx-auto space-y-10">

                {/* Business Model Canvas */}
                <section>
                    <h2 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4 flex items-center gap-2">
                        <Target className="w-3.5 h-3.5 text-[#F75105]" />
                        Business Model Canvas
                    </h2>
                    <div className="grid grid-cols-2 gap-4">
                        {bmcBlocks.map((block) => (
                            <div key={block.key} className="p-4 rounded-xl bg-[#2F323A] border border-white/5">
                                <label className="text-[10px] text-gray-500 uppercase tracking-widest font-bold block mb-2">
                                    {block.title}
                                </label>
                                <textarea
                                    value={bmc[block.key]}
                                    onChange={(e) => updateBMC(block.key, e.target.value)}
                                    placeholder={block.placeholder}
                                    className="w-full min-h-[120px] bg-transparent text-sm text-gray-300 placeholder:text-gray-600 focus:outline-none resize-none leading-relaxed"
                                />
                            </div>
                        ))}
                    </div>
                </section>

                {/* Action Plan */}
                <section>
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="text-xs text-gray-500 uppercase tracking-widest font-bold flex items-center gap-2">
                            <Zap className="w-3.5 h-3.5 text-amber-400" />
                            Plan d&apos;Action
                        </h2>
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => setShowActionInput(true)}
                            className="text-[#F75105] hover:text-[#F78E21] hover:bg-[#F75105]/10 text-xs"
                        >
                            <Plus className="w-3.5 h-3.5 mr-1" />
                            Ajouter
                        </Button>
                    </div>

                    {showActionInput && (
                        <div className="mb-4 flex gap-2">
                            <input
                                type="text"
                                value={newAction}
                                onChange={(e) => setNewAction(e.target.value)}
                                onKeyDown={(e) => e.key === "Enter" && addAction()}
                                placeholder="Nouvelle etape..."
                                className="flex-1 px-3 py-2 bg-[#2F323A] border border-white/10 rounded-lg text-sm text-white placeholder:text-gray-500 focus:outline-none focus:border-[#F75105]/50"
                                autoFocus
                            />
                            <Button onClick={addAction} size="sm" className="bg-[#F75105] hover:bg-[#F78E21] text-white">
                                OK
                            </Button>
                            <Button onClick={() => { setShowActionInput(false); setNewAction(""); }} variant="ghost" size="sm" className="text-gray-400">
                                <X className="w-4 h-4" />
                            </Button>
                        </div>
                    )}

                    {actions.length === 0 && !showActionInput ? (
                        <div className="text-center py-6 text-gray-500 text-sm">
                            Aucune action definie. Les leviers de votre analyse apparaitront ici.
                        </div>
                    ) : (
                        <div className="space-y-2">
                            {actions.map((action) => (
                                <div
                                    key={action.id}
                                    className={cn(
                                        "flex items-start gap-3 p-3 rounded-lg border transition-all",
                                        action.status === "done" ? "bg-emerald-500/5 border-emerald-500/10 opacity-70" : "bg-[#2F323A] border-white/5"
                                    )}
                                >
                                    <button
                                        onClick={() => toggleAction(action.id)}
                                        className={cn(
                                            "mt-0.5 w-5 h-5 rounded border flex items-center justify-center shrink-0 transition-colors",
                                            action.status === "done" ? "bg-emerald-500 border-emerald-500 text-white" : "border-gray-500 hover:border-[#F75105]"
                                        )}
                                    >
                                        {action.status === "done" && <Check className="w-3 h-3" />}
                                    </button>
                                    <div className="flex-1 min-w-0">
                                        <span className={cn(
                                            "text-xs",
                                            action.status === "done" ? "text-gray-500 line-through" : "text-gray-300"
                                        )}>
                                            {action.description}
                                        </span>
                                    </div>
                                    <span className={cn(
                                        "text-[9px] font-bold uppercase tracking-wider shrink-0 px-1.5 py-0.5 rounded",
                                        action.priority === "HIGH" ? "bg-emerald-500/10 text-emerald-400" :
                                        action.priority === "MEDIUM" ? "bg-amber-500/10 text-amber-400" :
                                        "bg-gray-500/10 text-gray-400"
                                    )}>
                                        {action.priority}
                                    </span>
                                    <button
                                        onClick={() => removeAction(action.id)}
                                        className="p-1 rounded text-gray-600 hover:text-gray-400 hover:bg-white/5 transition-colors shrink-0"
                                    >
                                        <X className="w-3.5 h-3.5" />
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </section>

                {/* Milestones */}
                <section>
                    <h2 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4 flex items-center gap-2">
                        <Calendar className="w-3.5 h-3.5 text-blue-400" />
                        Jalons
                    </h2>
                    <div className="grid grid-cols-2 gap-4">
                        {milestones.map((milestone, index) => (
                            <div key={milestone.id} className="p-4 rounded-xl bg-[#2F323A] border border-white/5">
                                <div className="flex items-center gap-2 mb-3">
                                    <div className="w-6 h-6 rounded-full bg-[#F75105]/10 text-[#F75105] flex items-center justify-center text-[10px] font-bold">
                                        {index + 1}
                                    </div>
                                    <input
                                        type="text"
                                        value={milestone.title}
                                        onChange={(e) => updateMilestone(milestone.id, "title", e.target.value)}
                                        className="flex-1 bg-transparent text-sm font-medium text-white focus:outline-none"
                                    />
                                </div>
                                <input
                                    type="date"
                                    value={milestone.targetDate}
                                    onChange={(e) => updateMilestone(milestone.id, "targetDate", e.target.value)}
                                    className="w-full px-3 py-1.5 bg-[#22242B] border border-white/5 rounded-lg text-xs text-gray-400 focus:outline-none focus:border-[#F75105]/50"
                                />
                            </div>
                        ))}
                    </div>
                </section>
            </div>
        </main>
    );
}

